    "bim.geo_depth_base": "Profundidad",
    "bim.geo_diagonal_base": "Diagonal",
    "bim.geo_footprint_base": "Huella",
    "bim.geo_height_base": "Altura",
    "bim.geo_width_base": "Ancho",
