    "files.context.open_in": "Abrir en {{module}}",
    "files.context.open_in_pdf_takeoff": "Abrir en PDF Takeoff",
    "files.context.view_pdf": "Ver PDF",
    "files.tile.tooltip_view": "{{name}} - haz doble clic para ver",
    "finance.confirm_pay_msg_immutable": "Esto registra el pago como un asiento contable inmutable y cierra la factura. No se puede deshacer.",
    "finance.invoice_sent_for_approval": "Factura enviada para aprobación",
    "finance.send_for_approval": "Enviar para aprobación",
    "finance.send_for_approval_failed": "No se pudo enviar la factura para aprobación",
    "finance.send_for_approval_hint": "Pasa esta factura en borrador a pendiente para que un responsable pueda aprobarla.",
    "finance.status_current": "actual",
    "finance.status_edit_hint": "Mueve la factura entre borrador, pendiente y cancelada. Aprobar una factura y marcarla como pagada se hace desde los botones Aprobar y Marcar pagada en la fila de la factura.",
    "finance.status_label": "Estado",
    "geo_hub.empty.no_anchor_description_v2": "Ancla automáticamente desde la dirección que definiste en los ajustes del proyecto, o elige una coordenada manualmente. Puedes ajustar con precisión arrastrando una vez que se coloque el marcador.",
    "geo_hub.empty.no_anchor_description_v3": "Ancla automáticamente desde la dirección que definiste en los ajustes del proyecto, o coloca un marcador directamente en el mapa. Puedes ajustar con precisión arrastrando una vez que se coloque el marcador.",
